var raw = $input.first().json;
var body = raw.body || raw;
var data = body.data || body;
var tenantId = String(body.tenantId || data.tenantId || '');
var id = String(data.id || data.previsionnelId || '');

function esc(v) {
  return v == null ? '' : String(v).replace(/'/g, "''");
}

const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(tenantId)) throw new Error('Invalid tenantId');
if (!uuidRegex.test(id)) throw new Error('Invalid id');

var query = "SELECT p.*, c.raison_sociale as client_raison_sociale, c.nom as client_nom, c.prenom as client_prenom, c.email as client_email, c.telephone as client_telephone, c.adresse as client_adresse FROM previsionnels p LEFT JOIN client_finals c ON p.client_final_id = c.id WHERE p.tenant_id = '" + esc(tenantId) + "' AND p.id = '" + esc(id) + "';";

return [{json: {query: query}}];

var row = $input.first().json;
if (!row || !row.id) {
  return [{json: {success: false, error: 'Prévisionnel non trouvé'}}];
}

var donnees = {};
try {
  donnees = typeof row.donnees === 'string' ? JSON.parse(row.donnees) : (row.donnees || {});
} catch(e) {
  donnees = {};
}

var clientLabel = row.client_raison_sociale || ((row.client_nom || '') + ' ' + (row.client_prenom || '')).trim() || null;

return [{json: {
  success: true,
  data: {
    id: row.id,
    tenantId: row.tenant_id,
    clientFinalId: row.client_final_id || null,
    clientLabel: clientLabel,
    clientEmail: row.client_email || null,
    clientTelephone: row.client_telephone || null,
    clientAdresse: row.client_adresse || null,
    nom: row.nom || 'Prévisionnel',
    description: row.description || null,
    annee: Number(row.annee || 0),
    statut: row.statut || 'brouillon',
    donnees: donnees,
    caAnnuel: Number(row.ca_annuel || 0),
    chargesAnnuelles: Number(row.charges_annuelles || 0),
    resultatExploitation: Number(row.resultat_exploitation || 0),
    seuilRentabilite: Number(row.seuil_rentabilite || 0),
    tresorerieFinale: Number(row.tresorerie_finale || 0),
    createdAt: row.created_at,
    updatedAt: row.updated_at
  }
}}];
